// ── Address autocomplete (Google Places Autocomplete API via fetch) ──────────
const MAPS_KEY = 'AIzaSyBR0WXiCAs16A502isiMtmGei5Rj-LvxBE';
let addrSession = crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36);
let addrActiveIdx = -1;
let addrTimeout = null;
let addrItems = [];

async function addrInput(val) {
  clearTimeout(addrTimeout);
  if (val.length < 3) { addrHide(); return; }
  addrTimeout = setTimeout(() => addrFetch(val), 250);
}

async function addrFetch(input) {
  try {
    // Uses the Places API (New) - supports CORS from any origin
    const res = await fetch('https://places.googleapis.com/v1/places:autocomplete', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Goog-Api-Key': MAPS_KEY,
      },
      body: JSON.stringify({
        input,
        includedRegionCodes: ['us'],
        includedPrimaryTypes: ['address'],
        sessionToken: addrSession,
      })
    });
    const data = await res.json();
    if (data.suggestions && data.suggestions.length) {
      addrShow(data.suggestions);
    } else {
      addrHide();
    }
  } catch(e) {
    addrHide();
  }
}

function addrShow(suggestions) {
  addrItems = suggestions;
  addrActiveIdx = -1;
  const dropdown = document.getElementById('addr-dropdown');
  dropdown.innerHTML = suggestions.slice(0, 6).map((s, i) => {
    // New Places API format: s.placePrediction
    const p = s.placePrediction || s;
    const text = p.text?.text || p.description || '';
    const parts = text.split(',');
    const main = parts[0] || text;
    const sub  = parts.slice(1).join(',').trim();
    return `<div class="addr-item" data-idx="${i}" onmousedown="addrSelect(${i})">
      <div class="addr-item-main">${main}</div>
      ${sub ? `<div class="addr-item-sub">${sub}</div>` : ''}
    </div>`;
  }).join('');
  dropdown.style.display = 'block';
}

function addrHide() {
  const d = document.getElementById('addr-dropdown');
  if (d) d.style.display = 'none';
  addrActiveIdx = -1;
}

function addrSelect(idx) {
  const s = addrItems[idx];
  if (!s) return;
  const p = s.placePrediction || s;
  const text = p.text?.text || p.description || '';
  document.getElementById('job-address').value = text;
  addrHide();
  // Reset session token after selection
  addrSession = crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36);
}

function addrKeydown(e) {
  const dropdown = document.getElementById('addr-dropdown');
  if (!dropdown || dropdown.style.display === 'none') return;
  const items = dropdown.querySelectorAll('.addr-item');
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    addrActiveIdx = Math.min(addrActiveIdx + 1, items.length - 1);
    items.forEach((el, i) => el.classList.toggle('active', i === addrActiveIdx));
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    addrActiveIdx = Math.max(addrActiveIdx - 1, -1);
    items.forEach((el, i) => el.classList.toggle('active', i === addrActiveIdx));
  } else if (e.key === 'Enter') {
    if (addrActiveIdx >= 0) { e.preventDefault(); addrSelect(addrActiveIdx); }
    else addrHide();
  } else if (e.key === 'Escape') {
    addrHide();
  }
}

