let roomCount = 0;
let equipCount = {};

// ── Equipment ────────────────────────────────────────────────────────────────
const EQUIP_TYPES = ['Dehumidifier','Air Mover','Air Scrubber','Other'];


const ROOM_SUGGESTIONS = [
  'Master Bedroom','Master Bathroom','Living Room','Family Room','Kitchen',
  'Dining Room','Guest Bedroom','Guest Bathroom','Hallway','Laundry Room',
  'Garage','Basement','Attic','Office','Pantry','Utility Room',
  'Mudroom','Foyer','Bedroom 2','Bedroom 3','Bathroom 2','Half Bath',
  'Walk-in Closet','Sunroom','Den','Bonus Room','Storage Room','Crawl Space'
];

let pendingRoomCallback = null;
let activeSuggestionIndex = -1;

function promptRoomName() {
  return new Promise(resolve => {
    pendingRoomCallback = resolve;
    const modal = document.getElementById('room-name-modal');
    const input = document.getElementById('room-name-modal-input');
    input.value = '';
    modal.style.display = 'flex';
    setTimeout(() => input.focus(), 50);
    filterRoomSuggestions();
  });
}

function confirmAddRoom() {
  const input = document.getElementById('room-name-modal-input');
  const name = input.value.trim() || `Room ${roomCount + 1}`;
  document.getElementById('room-name-modal').style.display = 'none';
  document.getElementById('room-suggestions').style.display = 'none';
  if (pendingRoomCallback) { pendingRoomCallback(name); pendingRoomCallback = null; }
}

function cancelAddRoom() {
  document.getElementById('room-name-modal').style.display = 'none';
  document.getElementById('room-suggestions').style.display = 'none';
  pendingRoomCallback = null;
}

function filterRoomSuggestions() {
  const input = document.getElementById('room-name-modal-input');
  const query = input.value.toLowerCase();
  const box = document.getElementById('room-suggestions');
  activeSuggestionIndex = -1;
  const matches = ROOM_SUGGESTIONS.filter(r =>
    query === '' || r.toLowerCase().includes(query)
  ).slice(0, 6);
  if (matches.length === 0) { box.style.display = 'none'; return; }
  box.innerHTML = matches.map((r, i) =>
    `<div class="modal-suggestion-item" data-index="${i}" onclick="selectRoomSuggestion('${r}')">${r}</div>`
  ).join('');
  box.style.display = 'block';
}

function selectRoomSuggestion(name) {
  document.getElementById('room-name-modal-input').value = name;
  document.getElementById('room-suggestions').style.display = 'none';
}

function handleModalKey(e) {
  const box = document.getElementById('room-suggestions');
  const items = box.querySelectorAll('.modal-suggestion-item');
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    activeSuggestionIndex = Math.min(activeSuggestionIndex + 1, items.length - 1);
    items.forEach((el, i) => el.classList.toggle('active', i === activeSuggestionIndex));
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    activeSuggestionIndex = Math.max(activeSuggestionIndex - 1, -1);
    items.forEach((el, i) => el.classList.toggle('active', i === activeSuggestionIndex));
  } else if (e.key === 'Enter') {
    e.preventDefault();
    if (activeSuggestionIndex >= 0 && items[activeSuggestionIndex]) {
      selectRoomSuggestion(items[activeSuggestionIndex].textContent);
    } else {
      confirmAddRoom();
    }
  } else if (e.key === 'Escape') {
    cancelAddRoom();
  }
}

function buildEquipRow(eid, selectedType, qty) {
  const opts = EQUIP_TYPES.map(t =>
    `<option${t === selectedType ? ' selected' : ''}>${t}</option>`
  ).join('');
  const isOther = selectedType === 'Other';
  return `
    <select onchange="toggleOtherInput(this, '${eid}')"
      style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 8px;font-size:13px;font-family:var(--sans);background:#fafafa;width:100%">
      ${opts}
    </select>
    <input type="text" id="other-label-${eid}" placeholder="Describe equipment"
      style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fafafa;width:100%;display:${isOther ? '' : 'none'}">
    <input type="number" value="${qty}" min="1" placeholder="Qty"
      style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fafafa;width:60px;flex-shrink:0">
    <button class="del-mat" onclick="document.getElementById('${eid}').remove()">×</button>
  `;
}

function toggleOtherInput(selectEl, eid) {
  const labelInput = document.getElementById('other-label-' + eid);
  if (labelInput) labelInput.style.display = selectEl.value === 'Other' ? '' : 'none';
}


// ── JobNimbus Integration ─────────────────────────────────────────────────────
// Auth token is handled server-side via the /jnapi proxy
const JN_BASE  = '/jnapi'; // proxied via proxy.js to app.jobnimbus.com/api1

function jnStatus(msg, type = '') {
  const el = document.getElementById('jn-status');
  el.textContent = msg;
  el.className = 'jn-status ' + type;
}

async function searchJNJobs() {
  const q = document.getElementById('jn-search-input').value.trim();
  if (!q) { jnStatus('Enter a search term.', 'error'); return; }

  const btn = document.getElementById('jn-search-btn');
  btn.disabled = true;
  jnStatus('Searching…', 'loading');
  document.getElementById('jn-results').style.display = 'none';

  try {
    // Search contacts first (jobs are linked to contacts in JobNimbus)
    const url = `${JN_BASE}/jobs?limit=25&q=${encodeURIComponent(q)}`;
    const resp = await fetch(url, {
      // No auth header needed — added by server proxy
    });

    if (!resp.ok) {
      jnStatus(`API error: ${resp.status} ${resp.statusText}`, 'error');
      return;
    }

    const data = await resp.json();
    const jobs = data.results || [];

    if (!jobs.length) {
      jnStatus('No jobs found. Try a different search.', 'error');
      return;
    }

    jnStatus(`Found ${jobs.length} job${jobs.length !== 1 ? 's' : ''}.`, 'success');
    renderJNResults(jobs);
  } catch (err) {
    jnStatus('Network error — check connection.', 'error');
    console.error('JN error:', err);
  } finally {
    btn.disabled = false;
  }
}

function renderJNResults(jobs) {
  const box = document.getElementById('jn-results');
  box.innerHTML = jobs.map((job, i) => {
    const name    = job.name || job.number || 'Unnamed Job';
    const contact = [job.first_name, job.last_name].filter(Boolean).join(' ');
    const addr    = [job.address_line1, job.city, job.state_text || job.state]
                      .filter(Boolean).join(', ');
    const status  = job.status_name || '';
    const meta    = [contact, addr, status].filter(Boolean).join('  ·  ');
    return `<div class="jn-result-item" onclick="loadJNJob(${i})">
      <div class="jn-result-name">${name}</div>
      ${meta ? `<div class="jn-result-meta">${meta}</div>` : ''}
    </div>`;
  }).join('');
  box._jobs = jobs;
  box.style.display = 'block';
}

function loadJNJob(index) {
  const box = document.getElementById('jn-results');
  const job = box._jobs[index];
  if (!job) return;

  // ── Map JobNimbus fields → form fields ─────────────────────────────────────
  // Client name: prefer contact name, fall back to job name
  const clientName = [job.first_name, job.last_name].filter(Boolean).join(' ')
                     || job.name || '';

  // Address: combine parts
  const addrParts = [
    job.address_line1,
    job.address_line2,
    job.city,
    job.state_text || job.state,
    job.zip
  ].filter(Boolean);
  const address = addrParts.join(', ');

  // Insurance info — JobNimbus stores these under various field names
  const insurer  = job.insurance_company || job.insurer || job.claim_company || '';
  const claimNum = job.claim_number || job.claim_num || job.insurance_claim_id || '';

  // Dates — JobNimbus uses Unix timestamps (seconds)
  function jnDate(ts) {
    if (!ts) return '';
    const d = new Date(ts * 1000);
    return d.toISOString().split('T')[0]; // YYYY-MM-DD for <input type=date>
  }
  const dateLoss  = jnDate(job.date_of_loss || job.loss_date || job.created);
  const dateStart = jnDate(job.start_date || job.date_start || job.created);

  // Fill form fields
  const set = (id, val) => { const el = document.getElementById(id); if (el && val) el.value = val; };
  set('client-name', clientName);
  set('job-address', address);
  set('ins-company', insurer);
  set('claim-num',   claimNum);
  set('date-loss',   dateLoss);
  set('date-start',  dateStart);

  // Close results, show confirmation
  document.getElementById('jn-results').style.display = 'none';
  document.getElementById('jn-search-input').value = '';
  jnStatus(`✓ Loaded: ${job.name || clientName}`, 'success');
  setTimeout(() => jnStatus(''), 4000);
}

function addEquipWithDefaults(roomId, type, qty) {
  if (!equipCount[roomId]) equipCount[roomId] = 0;
  const id = ++equipCount[roomId];
  const eid = `equip-${roomId}-${id}`;
  const div = document.createElement('div');
  div.className = 'equip-row';
  div.id = eid;
  div.innerHTML = buildEquipRow(eid, type, qty);
  document.getElementById('equip-list-' + roomId).appendChild(div);
}

function addEquip(roomId) {
  if (!equipCount[roomId]) equipCount[roomId] = 0;
  const id = ++equipCount[roomId];
  const eid = `equip-${roomId}-${id}`;

  const listEl = document.getElementById('equip-list-' + roomId);
  const usedTypes = listEl
    ? Array.from(listEl.querySelectorAll('select')).map(s => s.value).filter(v => v !== 'Other')
    : [];

  // Pick the first non-Other type not yet listed; fall back to Other
  const nextType = EQUIP_TYPES.find(t => t !== 'Other' && !usedTypes.includes(t)) || 'Other';

  const div = document.createElement('div');
  div.className = 'equip-row';
  div.id = eid;
  div.innerHTML = buildEquipRow(eid, nextType, 1);
  document.getElementById('equip-list-' + roomId).appendChild(div);
}

// ── Rooms ─────────────────────────────────────────────────────────────────────
const MATERIALS = Object.keys(MATERIAL_RATES);


async function duplicateRoom(sourceId) {
  // Prompt for new name first
  const name = await promptRoomName();
  if (!name) return;

  const sourceCard = document.getElementById('room-' + sourceId);
  if (!sourceCard) return;

  const id = ++roomCount;
  const div = document.createElement('div');
  div.className = 'room-card';
  div.id = 'room-' + id;

  // ── Copy room body HTML, remap all IDs and event listeners ────────────
  // Get the source body HTML and rewrite IDs
  const sourceBody = document.getElementById('room-body-' + sourceId);
  let bodyHTML = sourceBody.innerHTML;

  // Replace source room id references with new room id
  // We do a broad replace of the pattern -${sourceId}- or -${sourceId}" etc.
  const sid = String(sourceId);
  const nid = String(id);

  // Replace IDs and references embedded in the HTML
  // Use a function to replace all occurrences carefully
  function reId(str, oldId, newId) {
    // Replace patterns like: id="${prefix}-${oldId}" and onchange/oninput refs
    const patterns = [
      // id="xxx-OLDID-yyy" or id="xxx-OLDID"
      new RegExp('id="([^"]*?-|[^"]*?\\-)' + oldId + '(-[^"]*|")', 'g'),
      // for="xxx-OLDID"  (labels)
      new RegExp('for="([^"]*?-)' + oldId + '(-[^"]*|")', 'g'),
      // getElementById('xxx-OLDID')
      new RegExp("getElementById\\('([^']*?-)" + oldId + "(-[^']*|')", 'g'),
      // calcPsychro(OLDID)
      new RegExp('calcPsychro\\(' + oldId + '\\)', 'g'),
      // addMaterial(OLDID)
      new RegExp('addMaterial\\(' + oldId + '\\)', 'g'),
      // addEquip(OLDID)
      new RegExp('addEquip\\(' + oldId + '\\)', 'g'),
      // toggleRoom(OLDID)
      new RegExp('toggleRoom\\(' + oldId + '\\)', 'g'),
      // duplicateRoom(OLDID)
      new RegExp('duplicateRoom\\(' + oldId + '\\)', 'g'),
      // room-OLDID
      new RegExp('room-' + oldId + '(?=[^0-9]|$)', 'g'),
      // temp-OLDID  rh-OLDID  gpp-OLDID  dp-OLDID
      new RegExp('(temp-|rh-|gpp-|dp-)' + oldId, 'g'),
      // equip-list-OLDID
      new RegExp('equip-list-' + oldId, 'g'),
      // materials-OLDID
      new RegExp('materials-' + oldId, 'g'),
      // mat-OLDID-  (material row IDs)
      new RegExp('mat-' + oldId + '-', 'g'),
      // equip-OLDID-
      new RegExp('equip-' + oldId + '-', 'g'),
      // auto-studs references
      new RegExp('auto-studs-mat-' + oldId + '-', 'g'),
      new RegExp('auto-studs-day-mat-' + oldId + '-', 'g'),
    ];
    patterns.forEach(p => {
      str = str.replace(p, m => m.replace(new RegExp(oldId, 'g'), newId));
    });
    return str;
  }

  bodyHTML = reId(bodyHTML, sid, nid);

  div.innerHTML = `
    <div class="room-header" onclick="toggleRoom(${id})">
      <div class="room-header-left">
        <span class="room-tag">ROOM ${id}</span>
        <input type="text" class="room-name-input" value="${name}"
          style="border:none;background:none;font-size:14px;font-weight:600;font-family:var(--sans);color:var(--ink);width:180px;cursor:text"
          onclick="event.stopPropagation()"
          oninput="document.getElementById('room-name-display-${id}').textContent=this.value">
      </div>
      <div style="display:flex;align-items:center;gap:8px">
        <button class="remove-btn" onclick="event.stopPropagation();duplicateRoom(${id})" style="color:#555;border-color:#ccc;">Duplicate</button>
        <button class="remove-btn" onclick="event.stopPropagation();document.getElementById('room-${id}').remove()">Remove</button>
        <span style="font-size:18px;color:#ccc" id="room-chevron-${id}">▾</span>
      </div>
    </div>
    <div class="room-body" id="room-body-${id}">
      ${bodyHTML}
    </div>
  `;

  document.getElementById('rooms-list').appendChild(div);

  // Copy the live psychrometric input values from source
  const srcTemp = document.getElementById('temp-' + sourceId);
  const srcRh   = document.getElementById('rh-'   + sourceId);
  if (srcTemp) { const el = document.getElementById('temp-' + id); if (el) el.value = srcTemp.value; }
  if (srcRh)   { const el = document.getElementById('rh-'   + id); if (el) el.value = srcRh.value;   }
  calcPsychro(id);
}

