function toggleRoom(id) {
  const body = document.getElementById('room-body-' + id);
  const chev = document.getElementById('room-chevron-' + id);
  const hidden = body.style.display === 'none';
  body.style.display = hidden ? '' : 'none';
  chev.textContent = hidden ? '▾' : '▸';
}

let matCount = {};
function addMaterial(roomId) {
  if (!matCount[roomId]) matCount[roomId] = 0;
  const mid = ++matCount[roomId];
  const eid = `mat-${roomId}-${mid}`;
  const div = document.createElement('div');
  div.className = 'material-row';
  div.id = eid;
  div.innerHTML = `
    <select style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 8px;font-size:13px;font-family:var(--sans);background:#fafafa;width:100%">
      ${MATERIALS.map(m => `<option>${m}</option>`).join('')}
    </select>
    <input type="text" placeholder="e.g. North wall, lower 2ft" style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fafafa;width:100%">
    <input type="number" placeholder="100" value="100" min="0" max="100" step="0.1" style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fafafa;width:100%" title="Initial MC%">
    <input type="number" placeholder="Final%" min="0" max="100" step="0.1" style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fafafa;width:100%" title="Final MC%">
    <div style="display:flex;align-items:center;justify-content:center;height:34px;">
      <input type="checkbox" id="demo-chk-${eid}" onchange="toggleDemoDay('${eid}')" style="width:18px;height:18px;cursor:pointer;accent-color:var(--red)">
    </div>
    <input type="number" id="demo-day-${eid}" placeholder="Day #" min="1" max="7" style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 8px;font-size:13px;font-family:var(--mono);background:#f0f0f0;width:100%;display:none" disabled>
    <button class="del-mat" onclick="document.getElementById('${eid}').remove()">×</button>
  `;
  document.getElementById('materials-' + roomId).appendChild(div);
}

// ── Demo day toggle ─────────────────────────────────────────────────────────
function toggleDemoDay(eid) {
  const chk = document.getElementById('demo-chk-' + eid);
  const dayInput = document.getElementById('demo-day-' + eid);
  if (chk.checked) {
    dayInput.style.display = '';
    dayInput.disabled = false;
    dayInput.style.background = '#fafafa';
  } else {
    dayInput.style.display = 'none';
    dayInput.disabled = true;
    dayInput.value = '';
    // Remove any auto-added studs row linked to this drywall
    const linkedStuds = document.getElementById('auto-studs-' + eid);
    if (linkedStuds) linkedStuds.remove();
  }

  // Check if this row is a Drywall row
  const row = document.getElementById(eid);
  if (!row) return;
  const matSel = row.querySelector('select');
  if (!matSel || matSel.value !== 'Drywall') return;

  if (chk.checked) {
    // Auto-add studs when drywall is demoed — listen for demo day input
    dayInput.addEventListener('input', syncStudsDemoDay.bind(null, eid), { once: false });
    // Add studs row immediately if not already present
    addAutoStuds(eid, dayInput.value);
  } else {
    const linkedStuds = document.getElementById('auto-studs-' + eid);
    if (linkedStuds) linkedStuds.remove();
  }
}

function addAutoStuds(drywallEid, demoDay) {
  // Don't add if already exists
  if (document.getElementById('auto-studs-' + drywallEid)) return;

  // Find the room this drywall row belongs to
  const drywallRow = document.getElementById(drywallEid);
  if (!drywallRow) return;
  const materialsContainer = drywallRow.parentElement;
  const roomId = drywallEid.split('-')[1];

  if (!matCount[roomId]) matCount[roomId] = 0;
  const mid = ++matCount[roomId];
  const studsEid = `mat-${roomId}-${mid}`;

  const div = document.createElement('div');
  div.className = 'material-row';
  div.id = 'auto-studs-' + drywallEid; // track by drywall eid
  div.style.background = '#fffbf0';
  div.style.borderRadius = '6px';
  div.style.padding = '2px 4px';

  div.innerHTML = `
    <select style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 8px;font-size:13px;font-family:var(--sans);background:#fffbf0;width:100%">
      ${MATERIALS.map(m => `<option${m === 'Studs' ? ' selected' : ''}>${m}</option>`).join('')}
    </select>
    <input type="text" value="Auto-added (drywall demo)" style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fffbf0;width:100%">
    <input type="number" value="100" min="0" max="100" step="0.1" style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fffbf0;width:100%" title="Initial MC%">
    <input type="number" placeholder="Final%" min="0" max="100" step="0.1" style="height:34px;border:1px solid var(--border);border-radius:7px;padding:0 10px;font-size:13px;font-family:var(--mono);background:#fffbf0;width:100%" title="Final MC%">
    <div style="display:flex;align-items:center;justify-content:center;height:34px;">
      <input type="checkbox" style="width:18px;height:18px;cursor:pointer;accent-color:var(--red)" disabled>
    </div>
    <input type="number" id="auto-studs-day-${drywallEid}" placeholder="Day #" min="1" max="7"
      value="${demoDay || ''}"
      style="height:34px;border:1px solid #f0c080;border-radius:7px;padding:0 8px;font-size:13px;font-family:var(--mono);background:#fff8e8;width:100%" title="Start day (from drywall demo day)">
    <button class="del-mat" onclick="document.getElementById('auto-studs-${drywallEid}').remove()" title="Remove">×</button>
  `;

  // Insert right after the drywall row
  drywallRow.insertAdjacentElement('afterend', div);
}

function syncStudsDemoDay(drywallEid) {
  const dayInput = document.getElementById('demo-day-' + drywallEid);
  const studsDay = document.getElementById('auto-studs-day-' + drywallEid);
  if (!document.getElementById('auto-studs-' + drywallEid)) {
    addAutoStuds(drywallEid, dayInput.value);
    return;
  }
  if (studsDay) studsDay.value = dayInput.value;
}

// ── Psychrometrics ───────────────────────────────────────────────────────────
function calcPsychro(roomId) {
  const tempF = parseFloat(document.getElementById('temp-' + roomId).value);
  const rh    = parseFloat(document.getElementById('rh-' + roomId).value);
  if (isNaN(tempF) || isNaN(rh)) return;

  const tempC = (tempF - 32) * 5/9;

  // Saturation vapor pressure (Magnus formula)
  const es = 6.112 * Math.exp((17.67 * tempC) / (tempC + 243.5));
  const e  = es * (rh / 100);

  // GPP: grains per pound of dry air
  const pa   = 101.325; // kPa approx sea level
  const w    = 0.622 * e / (pa - e); // humidity ratio kg/kg
  const gpp  = w * 7000;             // convert to grains/lb

  // Dew point (Magnus approximation)
  const gamma = Math.log(e / 6.112);
  const dpC   = (243.5 * gamma) / (17.67 - gamma);
  const dpF   = dpC * 9/5 + 32;

  document.getElementById('gpp-' + roomId).textContent = gpp.toFixed(1);
  document.getElementById('dp-'  + roomId).textContent = dpF.toFixed(1) + '°F';
}

// ── Project moisture readings (smooth-step S-curve) ─────────────────────────
function projectReadings(material, initialMC, finalMC, days, demoed, demoDay, startDay) {
  const dry   = DRY_STANDARD[material] ?? 15;
  const start = startDay || 1;

  const endDay     = (demoed && demoDay) ? demoDay - 1 : days;
  const activeDays = endDay - start + 1;

  // Target: if tech entered a final reading use it, otherwise curve to dry standard
  const target = (finalMC != null && !demoed) ? finalMC : dry;

  const seed = initialMC * 7.3 + (start) * 13.1 + material.length * 3.7;
  function seededRand(day) {
    const x = Math.sin(seed + day * 127.1) * 43758.5453;
    return x - Math.floor(x);
  }

  const rows = [];
  for (let d = 1; d <= days; d++) {
    if (d < start) {
      rows.push({ day: d, mc: null, notStarted: true });
    } else if (demoed && demoDay && d >= demoDay) {
      rows.push({ day: d, mc: null, demoed: true });
    } else {
      const t = d - start; // 0-indexed active step

      let mc;
      if (activeDays <= 1) {
        mc = target;
      } else if (t === 0) {
        // Day 1 always exact initial reading
        mc = initialMC;
      } else if (t === activeDays - 1) {
        // Last active day always lands exactly on final reading / dry standard
        mc = target;
      } else {
        // Smooth-step S-curve: slow start → fast middle → slow finish
        // Mimics real drying: equipment ramp-up, peak extraction, asymptote
        const frac   = t / (activeDays - 1);          // linear 0→1
        const smooth = frac * frac * (3 - 2 * frac);  // smooth-step: 3f²-2f³
        const baseMC = initialMC + (target - initialMC) * smooth;

        // Small natural variability ±1.5–2.5%, never fall below target
        const varRange = 0.015 + seededRand(d) * 0.01;
        const sign     = seededRand(d + 50) > 0.5 ? 1 : -1;
        mc = Math.max(target, baseMC + baseMC * varRange * sign);
      }

      rows.push({ day: d, mc: parseFloat(mc.toFixed(1)), demoed: false });
    }
  }
  return rows;
}

// ── Collect form data ────────────────────────────────────────────────────────

// ── Review modal ─────────────────────────────────────────────────────────────
let reviewData = null; // holds collected + projected data for editing

function openReview() {
  const data = collectData();
  if (!data.rooms.length) { alert('Please add at least one room.'); return; }
  reviewData = data;
  buildReviewUI(data);
  document.getElementById('review-modal').style.display = 'flex';
  document.getElementById('review-modal').scrollTop = 0;
}

function closeReview() {
  document.getElementById('review-modal').style.display = 'none';
  reviewData = null;
}

function buildReviewUI(data) {
  const days = data.days;
  const dayHeaders = Array.from({length: days}, (_, i) =>
    `<th>Day ${i + 1}${i === 0 ? '<br><span style="font-weight:400;font-size:9px">(Initial)</span>' : ''}</th>`
  ).join('');

  let html = '';

  data.rooms.forEach((room, ri) => {
    if (!room.materials.length) return;
    html += `<div class="review-room-block">`;
    html += `<div class="review-room-label">Room ${ri + 1}: ${room.name}</div>`;
    html += `<table class="review-table" id="review-table-${ri}">`;
    html += `<thead><tr><th>Material</th><th>Final MC</th>${dayHeaders}</tr></thead>`;
    html += `<tbody id="review-tbody-${ri}">`;
    html += buildReviewRows(room, ri, days);
    html += '</tbody></table></div>';
  });

  document.getElementById('review-content').innerHTML = html;
}

function buildReviewRows(room, ri, days) {
  let html = '';
  room.materials.forEach((mat, mi) => {
    html += buildReviewRow(mat, ri, mi, days);
  });
  return html;
}

function buildReviewRow(mat, ri, mi, days) {
  const finalCell = mat.demoed
    ? `<td><span class="review-cell-demo">DEMO'd D${mat.demoDay || '?'}</span></td>`
    : `<td><input class="review-cell-input" type="number" step="0.1" min="0" max="100"
          value="${mat.finalMC != null ? mat.finalMC : ''}"
          placeholder="–"
          oninput="updateFinalMC(${ri},${mi},this.value)"
          title="Final MC% — editing recalculates projections"></td>`;

  const dayCells = mat.projection.map((p, di) => {
    if (p.demoed)     return `<td><span class="review-cell-demo">DEMO</span></td>`;
    if (p.notStarted) return `<td style="color:#ccc">–</td>`;
    return `<td><input class="review-cell-input" type="number" step="0.1" min="0" max="100"
        value="${p.mc != null ? p.mc : ''}"
        oninput="updateProjectionCell(${ri},${mi},${di},this.value)"
        title="Day ${di+1} MC%"></td>`;
  }).join('');

  return `<tr id="review-row-${ri}-${mi}">
    <td>${mat.material}</td>
    ${finalCell}
    ${dayCells}
  </tr>`;
}

function updateProjectionCell(ri, mi, di, val) {
  if (!reviewData) return;
  const mc = val === '' ? null : parseFloat(val);
  reviewData.rooms[ri].materials[mi].projection[di].mc = isNaN(mc) ? null : mc;
}

function updateFinalMC(ri, mi, val) {
  if (!reviewData) return;
  const mat = reviewData.rooms[ri].materials[mi];
  mat.finalMC = val === '' ? null : parseFloat(val);
  if (isNaN(mat.finalMC)) mat.finalMC = null;

  // Recalculate projections with updated finalMC
  mat.projection = projectReadings(
    mat.material, mat.initialMC, mat.finalMC,
    reviewData.days, mat.demoed, mat.demoDay, mat.startDay
  );

  // Re-render just this row in the DOM
  const rowEl = document.getElementById(`review-row-${ri}-${mi}`);
  if (rowEl) {
    rowEl.outerHTML = buildReviewRow(mat, ri, mi, reviewData.days);
    // Refocus the finalMC input after re-render
    const newRow = document.getElementById(`review-row-${ri}-${mi}`);
    if (newRow) {
      const finalInput = newRow.querySelector('input[type=number]');
      if (finalInput) {
        finalInput.focus();
        // Move cursor to end
        const v = finalInput.value;
        finalInput.value = '';
        finalInput.value = v;
      }
    }
  }
}

function confirmGeneratePDF() {
  if (!reviewData) return;
  document.getElementById('review-modal').style.display = 'none';
  generateFromData(reviewData);
}

function collectData() {
  const days = parseInt(document.getElementById('dry-days').value);

  const rooms = [];
  document.querySelectorAll('.room-card').forEach(rc => {
    const id = rc.id.replace('room-', '');
    const name = rc.querySelector('.room-name-input').value;
    const tempF = parseFloat(document.getElementById('temp-' + id)?.value) || null;
    const rh    = parseFloat(document.getElementById('rh-'  + id)?.value) || null;

    let gpp = null, dp = null;
    if (tempF && rh) {
      const tempC = (tempF - 32) * 5/9;
      const es = 6.112 * Math.exp((17.67 * tempC) / (tempC + 243.5));
      const e  = es * (rh / 100);
      const pa = 101.325;
      const w  = 0.622 * e / (pa - e);
      gpp = (w * 7000).toFixed(1);
      const gamma = Math.log(e / 6.112);
      dp = ((243.5 * gamma / (17.67 - gamma)) * 9/5 + 32).toFixed(1);
    }

    const materials = [];
    rc.querySelectorAll('.material-row').forEach(mr => {
      const inputs  = mr.querySelectorAll('input');
      const sel     = mr.querySelector('select').value;
      const note    = inputs[0].value;
      const initMC  = parseFloat(inputs[1].value);
      const finalMC = parseFloat(inputs[2].value);
      const demoed  = inputs[3].checked;
      const demoDay = demoed ? parseInt(inputs[4].value) || null : null;
      // startDay: auto-studs rows have disabled checkbox, 5th input is start day
      const startDay = (inputs[3] && inputs[3].disabled) ? parseInt(inputs[4]?.value) || null : null;
      if (!isNaN(initMC)) {
        materials.push({
          material: sel,
          note,
          initialMC: initMC,
          finalMC: isNaN(finalMC) ? null : finalMC,
          demoed,
          demoDay,
          startDay,
          dryStd: DRY_STANDARD[sel],
          projection: projectReadings(sel, initMC, isNaN(finalMC) ? null : finalMC, days, demoed, demoDay, startDay)
        });
      }
    });

    const equipment = [];
    rc.querySelectorAll('.equip-row').forEach(er => {
      const sel   = er.querySelector('select');
      const type  = sel ? sel.value : '';
      const qty   = er.querySelector('input[type=number]') ? er.querySelector('input[type=number]').value : '1';
      const labelEl = er.querySelector('input[type=text]');
      const label = labelEl ? labelEl.value.trim() : '';
      equipment.push({ type, qty, label });
    });

    rooms.push({ name, tempF, rh, gpp, dp, materials, equipment });
  });

  return {
    client:    document.getElementById('client-name').value,
    claim:     document.getElementById('claim-num').value,
    address:   document.getElementById('job-address').value,
    insurer:   document.getElementById('ins-company').value,
    dateLoss:  document.getElementById('date-loss').value,
    dateStart: document.getElementById('date-start').value,
    days, rooms
  };
}

// ── Format date ──────────────────────────────────────────────────────────────
function fmtDate(str) {
  if (!str) return '–';
  const d = new Date(str + 'T00:00:00');
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function addDay(str, n) {
  if (!str) return '';
  const d = new Date(str + 'T00:00:00');
  d.setDate(d.getDate() + n);
  return d.toLocaleDateString('en-US', { month: 'M/d' });
}

// ── Generate PDF ─────────────────────────────────────────────────────────────
function generate() {
  openReview();
}

function generateFromData(data) {
  if (!data || !data.rooms.length) { alert('Please add at least one room.'); return; }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'letter' });

  const RED    = [192, 57, 43];
  const INK    = [26, 26, 26];
  const GRAY   = [120, 120, 120];
  const LGRAY  = [245, 245, 243];
  const WHITE  = [255, 255, 255];
  const GREEN  = [26, 122, 74];

  const W = 215.9, M = 14;
  let y = M;

  function pageCheck(need = 20) {
    if (y + need > 270) {
      doc.addPage();
      y = M;
      drawPageHeader();
    }
  }

  function drawPageHeader() {
    doc.setFillColor(245, 245, 243);
    doc.rect(0, 0, W, 10, 'F');
    doc.setDrawColor(220, 220, 220);
    doc.setLineWidth(0.3);
    doc.line(0, 10, W, 10);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(...INK);
    doc.text('A1 RESTORATION  |  DRYING LOG', M, 6.5);
    doc.setTextColor(...GRAY);
    doc.text(`CLAIM: ${data.claim || '–'}`, W - M, 6.5, { align: 'right' });
    y = 16;
  }

  // ── Cover header (slim) ─────────────────────────────────────────────────
  // Thin red accent bar at very top
  doc.setFillColor(...RED);
  doc.rect(0, 0, W, 2, 'F');

  // Logo: crop to content area — original logo is ~4:1 ratio, render short & wide
  try {
    // addImage(data, format, x, y, width, height, alias, compression, rotation)
    // Render tall portion of logo only by clipping via a small height
    doc.addImage(LOGO_B64, 'PNG', M, 4, 55, 13);
  } catch(e) {}

  // Subtitle right-aligned at baseline of logo
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.setTextColor(...GRAY);
  doc.text('IICRC S500 · WATER DAMAGE REPORT', W - M, 12, { align: 'right' });

  // Thin separator
  doc.setDrawColor(220, 220, 220);
  doc.setLineWidth(0.3);
  doc.line(M, 20, W - M, 20);

  y = 26;

  // ── Job info box ─────────────────────────────────────────────────────────
  doc.setFillColor(...LGRAY);
  doc.roundedRect(M, y, W - M*2, 28, 2, 2, 'F');

  const col1 = M + 4, col2 = M + 4 + (W - M*2)/2;
  const fields = [
    ['CLIENT', data.client || '–'],
    ['ADDRESS', data.address || '–'],
    ['DATE OF LOSS', fmtDate(data.dateLoss)],
    ['DRY START DATE', fmtDate(data.dateStart)],
    ['INSURANCE COMPANY', data.insurer || '–'],
    ['CLAIM NUMBER', data.claim || '–'],
  ];

  fields.forEach((f, i) => {
    const col = i % 2 === 0 ? col1 : col2;
    const row = Math.floor(i / 2);
    const fy = y + 6 + row * 8;
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(6.5);
    doc.setTextColor(...GRAY);
    doc.text(f[0], col, fy);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8.5);
    doc.setTextColor(...INK);
    doc.text(f[1], col, fy + 4);
  });

  y += 33;

  // ── Dry duration badge ───────────────────────────────────────────────────
  doc.setFillColor(...RED);
  doc.roundedRect(M, y, 48, 8, 2, 2, 'F');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(7);
  doc.setTextColor(...WHITE);
  doc.text(`DRYING LOG: ${data.days} DAYS  |  IICRC S500`, M + 3, y + 5.2);
  y += 13;

  // ── Rooms ────────────────────────────────────────────────────────────────
  data.rooms.forEach((room, ri) => {
    pageCheck(40);

    // Room header bar
    doc.setFillColor(...INK);
    doc.rect(M, y, W - M*2, 9, 'F');
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(...WHITE);
    doc.text(`ROOM ${ri + 1}: ${room.name.toUpperCase()}`, M + 4, y + 6);
    y += 13;

    // Psychrometrics
    if (room.tempF || room.rh) {
      pageCheck(18);
      const psychros = [
        ['TEMP (°F)', room.tempF ?? '–'],
        ['REL. HUMIDITY', room.rh ? room.rh + '%' : '–'],
        ['GPP', room.gpp ?? '–'],
        ['DEW POINT', room.dp ? room.dp + '°F' : '–'],
      ];

      const pw = (W - M*2) / 4;
      psychros.forEach((p, pi) => {
        const px = M + pi * pw;
        doc.setFillColor(...LGRAY);
        doc.rect(px, y, pw - 1, 14, 'F');
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(7);
        doc.setTextColor(...GRAY);
        doc.text(p[0], px + 3, y + 5);
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(11);
        doc.setTextColor(...INK);
        doc.text(String(p[1]), px + 3, y + 12);
      });
      y += 18;
    }

    // Equipment per room
    if (room.equipment && room.equipment.length) {
      pageCheck(20);
      doc.autoTable({
        startY: y,
        margin: { left: M, right: M },
        head: [['Equipment Type', 'Qty']],
        body: room.equipment.map(e => [e.type === 'Other' && e.label ? e.label : e.type, e.qty]),
        styles: { fontSize: 8, cellPadding: 2.5, font: 'helvetica' },
        headStyles: { fillColor: [80, 80, 80], textColor: WHITE, fontStyle: 'bold', fontSize: 7 },
        alternateRowStyles: { fillColor: [250, 250, 250] },
        columnStyles: { 1: { halign: 'center', cellWidth: 20 } },
        tableWidth: 80,
      });
      y = doc.lastAutoTable.finalY + 8;
    }

    // Moisture projection table
    if (room.materials.length) {
      pageCheck(30);

      const dayHeaders = Array.from({ length: data.days }, (_, i) => {
        const label = i === 0 ? 'Day 1\n(Initial)' : `Day ${i+1}`;
        return label;
      });

      const head = [['Material', 'Location', 'Dry Std%', 'Final MC%', ...dayHeaders]];
      const body = room.materials.map(mat => {
        const dryStd  = mat.dryStd != null ? mat.dryStd + '%' : 'N/A';
        const finalMC = mat.demoed
          ? { content: `DEMO'd Day ${mat.demoDay || '–'}`, styles: { textColor: [150,80,0], fontStyle: 'bold', fillColor: [255,243,220] } }
          : mat.finalMC != null
            ? { content: mat.finalMC + '%', styles: { textColor: mat.dryStd && mat.finalMC <= mat.dryStd ? GREEN : RED, fontStyle: 'bold' } }
            : { content: '–', styles: { textColor: GRAY } };
        const mcVals = mat.projection.map((p, di) => {
          if (p.demoed)     return { content: 'DEMO', styles: { textColor: [180,120,0], fontStyle: 'bold' } };
          if (p.notStarted) return { content: '–', styles: { textColor: GRAY } };
          const isDry = mat.dryStd != null && p.mc <= mat.dryStd;
          return { content: p.mc + '%', styles: { textColor: isDry ? GREEN : (di === 0 ? RED : INK), fontStyle: isDry ? 'bold' : 'normal' } };
        });
        return [mat.material, mat.note || '–', dryStd, finalMC, ...mcVals];
      });

      doc.autoTable({
        startY: y,
        margin: { left: M, right: M },
        head,
        body,
        styles: { fontSize: 8, cellPadding: 2.5, font: 'helvetica', halign: 'center' },
        headStyles: { fillColor: [60, 60, 60], textColor: WHITE, fontStyle: 'bold', fontSize: 7, halign: 'center' },
        columnStyles: {
          0: { halign: 'left', cellWidth: 26 },
          1: { halign: 'left', cellWidth: 34 },
          2: { cellWidth: 16 },
          3: { cellWidth: 18 },
        },
        alternateRowStyles: { fillColor: [250, 250, 250] },
      });
      y = doc.lastAutoTable.finalY + 10;
    }
  });

  // ── Footer / legend ──────────────────────────────────────────────────────
  pageCheck(24);
  doc.setFillColor(...LGRAY);
  doc.rect(M, y, W - M*2, 18, 'F');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8);
  doc.setTextColor(...GRAY);
  doc.text('LEGEND', M + 4, y + 5);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.setTextColor(...RED);
  doc.text('RED = above dry standard   ', M + 4, y + 11);
  doc.setTextColor(...GREEN);
  doc.text('GREEN = at or below dry standard (IICRC S500)', M + 60, y + 11);


  // ── Page numbers ─────────────────────────────────────────────────────────
  const totalPages = doc.internal.getNumberOfPages();
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(7);
    doc.setTextColor(...GRAY);
    doc.text(`Page ${i} of ${totalPages}`, W - M, 275, { align: 'right' });
    doc.text('A1 Restoration  |  Confidential – For Insurance Purposes', M, 275);
  }

  const filename = `DryingLog_${(data.client || 'Job').replace(/\s+/g,'_')}_${data.dateStart || 'undated'}.pdf`;
  doc.save(filename);

  document.getElementById('success-banner').style.display = 'flex';
  setTimeout(() => document.getElementById('success-banner').style.display = 'none', 4000);
}

// ── Init: default dates + first room ─────────────────────────────────────────
window.addEventListener('DOMContentLoaded', () => {
  const today = new Date().toISOString().split('T')[0];
  document.getElementById('date-start').value = today;
});